def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        base_ratio = item / cap
        if base_ratio > 2.0:
            priorities[idx] = np.inf
            continue
        total_score = 0.0
        decay = 1.0
        bonus = 0.0
        complex_factor = 1.0
        for m in range(1, 15):
            if m % 2 == 0:
                decay *= 0.97 + 0.005 * m
            elif m % 4 == 1:
                decay *= 1.03 - 0.007 * m
            contribution = (np.tanh(item / (cap + m)) + np.cos(m * base_ratio)) * decay
            if base_ratio < 0.25 * m:
                total_score += contribution * (m ** 1.5)
            else:
                total_score += np.log1p(contribution * m) / (m + 1)
            if (cap * m + item) % 9 == 0:
                total_score *= 1.03
            elif (cap + item * m) % 11 == 0:
                total_score *= 0.97
            if m == 5:
                for n in range(2, 7):
                    delta = cap - item * (n + m)
                    if delta > 0:
                        if delta % (n + 3) == 0:
                            bonus += np.sqrt(abs(delta)) / (n + m)
                        else:
                            bonus -= np.log1p(abs(delta)) / (n + m)
                    else:
                        bonus -= abs(delta) ** 1.5 / (n + m + 1)
            if base_ratio > 0.7 and m % 3 == 0:
                complex_factor *= 1.12 + 0.015 * m
            elif base_ratio < 0.15 and m % 5 == 0:
                complex_factor *= 0.88 - 0.012 * m
            if m % 6 == 1 and cap % (m + 2) != 0:
                bonus += np.sin(m * np.pi * base_ratio) * 0.7
            if m % 7 == 0 and int(cap) % 3 == 0:
                total_score += np.exp(-base_ratio * m) * 0.5
        total_score += bonus * 0.9
        total_score *= complex_factor
        if total_score <= 0:
            priorities[idx] = -total_score * (np.log1p(cap + item) * 1.2 + np.sqrt(cap) * 0.9)
        else:
            if cap > item * 3.5:
                priorities[idx] = -total_score / (np.sqrt(cap) + 2) * (1 + base_ratio ** 1.1)
            else:
                priorities[idx] = -total_score / (cap + 4) * np.exp(-base_ratio ** 1.7)
        if base_ratio > 0.9:
            priorities[idx] *= 1.18
        elif base_ratio < 0.1:
            priorities[idx] *= 0.72
        if cap % 3 == 0:
            priorities[idx] *= 0.95
        else:
            priorities[idx] *= 1.05
        if idx % 2 == 0:
            priorities[idx] *= 1.01
        else:
            priorities[idx] *= 0.99
    return priorities
